patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4bba2f406b4c..1f6bf5abd526 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2794,6 +2794,21 @@ static Instruction *foldSelectWithFCmpToFabs(SelectInst &SI,
     // fold (X <= +/-0.0) ? (0.0 - X) : X to fabs(X), when 'Swap' is false
     // fold (X >  +/-0.0) ? X : (0.0 - X) to fabs(X), when 'Swap' is true
     if (match(TrueVal, m_FSub(m_PosZeroFP(), m_Specific(X)))) {
+      // Require nnan to ensure NaN sign/canonicalization behavior is preserved.
+      // Allow if the select already has nnan, the fcmp condition has nnan,
+      // or the operand X is known to not be NaN via nofpclass(nan).
+      bool AllowNaNFold = false;
+      FastMathFlags CFMF = cast<FPMathOperator>(CondVal)->getFastMathFlags();
+      if (SI.hasNoNaNs() || CFMF.noNaNs()) {
+        AllowNaNFold = true;
+      } else if (auto *Arg = dyn_cast<Argument>(X)) {
+        FPClassTest NFT = Arg->getNoFPClass();
+        // If NaNs are excluded for X, then it's safe to fold.
+        if (NFT & fcNan)
+          AllowNaNFold = true;
+      }
+      if (!AllowNaNFold)
+        continue;
       if (!Swap && (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE)) {
         Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
         return IC.replaceInstUsesWith(SI, Fabs);

